sql:
SELECT DISTINCT machine_type
FROM machines
WHERE last_updated < '2023-04-01' AND last_compliance_check >= '2023-04-01';

SELECT location, compliance_status
FROM machines
WHERE machine_id = 1;

external_knowledge:
- 'recently troubled machines' refers to those that are marked as 'non-compliant';
- 'updated within the last couple of months' means last_updated within the past 2 months;
- 'non-compliance issues categorized under policies' refers to the policy categories and subcategories assigned to these machines.

sql:
SELECT machine_name, compliance_status
FROM machines
WHERE compliance_status = 'compliant';

SELECT machine_name
FROM machines
WHERE machine_id NOT IN (
    SELECT machine_id FROM machine_policy_assignments
);

SELECT department, COUNT(machine_id) AS number_of_machines
FROM machines
GROUP BY department;

SELECT DISTINCT department
FROM machines
WHERE compliance_status = 'non-compliant';
